#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int num;
        if (scanf("%d", &num) != 1) break;
        if (num % 3 == 0 && num % 5 == 0) {
            printf("Divisible by both 3 and 5\n");
        } else {
            printf("Not divisible by both 3 and 5\n");
        }
    }
    return 0;
}

